const q = (msg.req && msg.req.query) ? msg.req.query : {};
const wrap = String(q.wrap || '') === '1';

// Error from node
if (msg.error) {
  msg.statusCode = 500;
  msg.payload = { success: false, message: msg.error.message };
  return msg;
}

// Respect pre-set non-200 responses (validation/custom)
if (typeof msg.statusCode === 'number' && msg.statusCode !== 200 && msg.payload !== undefined) {
  return msg;
}

// Allow custom payloads (already final shape)
if (msg.skipAutoWrap) {
  msg.statusCode = msg.statusCode || 200;
  return msg;
}

msg.statusCode = msg.statusCode || 200;

// wrap!=1 => preserve original payload (rows/row/custom object)
if (!wrap) return msg;

const payload = msg.payload;

// rows array
if (Array.isArray(payload)) {
  msg.payload = { success: true, count: payload.length, data: payload };
  return msg;
}

// single row (object or null)
msg.payload = { success: payload != null, data: (payload == null ? null : payload) };
return msg;

const row = (Array.isArray(msg.payload) && msg.payload[0]) ? msg.payload[0] : null;
msg.payload = row;
return msg;

