const q = (msg.req && msg.req.query) ? msg.req.query : {};
const from = q.from;
const limit = q.limit ? Math.max(1, Math.min(100, Number(q.limit))) : 100;

let sql = `SELECT
  Sessions.start_date AS "Start Date/Time",
  Sessions.session_id AS "Session ID",
  Locations.name AS "Location",
  Chargers.name AS "Charger",
  Connectors.connector_type AS "Connector",
  ROUND(Sessions.kwh,2) AS "Energy (KWH)",
  ROUND(Sessions.amount,2) AS "Amount (JOD)",
  Sessions.user_id AS "mobile"
FROM Sessions
RIGHT JOIN Connectors ON Connectors.connector_id = Sessions.connector_id
RIGHT JOIN Chargers ON Chargers.charger_id = Sessions.charger_id
RIGHT JOIN Locations ON Locations.location_id = Chargers.location_id
WHERE Sessions.active=1`;

msg.payload = [];
if (from) { sql += ` AND Sessions.start_date > ?`; msg.payload.push(from); }
sql += ` GROUP BY Sessions.session_id ORDER BY Sessions.session_id DESC LIMIT ?;`;
msg.payload.push(limit);
msg.topic = sql;
msg.operation = 'ACTIVE_SESSIONS';
return msg;

